// Smart Resource Allocation Logic
const parsedTask = JSON.parse($('AI Task Parser').first().json.message.content);
const teamMembers = $('Fetch Team Workload').all().map(item => item.json);

// Filter by required skills (simplified matching)
let eligibleMembers = teamMembers.filter(member => {
  const memberSkills = member.skills.toLowerCase().split(',').map(s => s.trim());
  return parsedTask.required_skills.some(skill => 
    memberSkills.includes(skill.toLowerCase())
  );
});

// If no exact skill match, use all members
if (eligibleMembers.length === 0) {
  eligibleMembers = teamMembers;
}

// Find member with lowest current workload
let bestMember = eligibleMembers.reduce((prev, current) => {
  return (prev.current_hours < current.current_hours) ? prev : current;
});

// Calculate new workload
const newWorkload = parseFloat(bestMember.current_hours) + parsedTask.estimated_hours;

return [{
  json: {
    task_id: 'TASK-' + Date.now(),
    title: parsedTask.title,
    description: parsedTask.description,
    priority: parsedTask.priority,
    estimated_hours: parsedTask.estimated_hours,
    required_skills: parsedTask.required_skills.join(', '),
    task_type: parsedTask.task_type,
    assigned_to: bestMember.name,
    assigned_email: bestMember.email,
    assigned_slack_id: bestMember.slack_id,
    previous_workload: bestMember.current_hours,
    new_workload: newWorkload,
    status: 'To Do',
    created_by: $('Task Request Webhook').first().json.requester,
    created_at: $now.toISO(),
    deadline: $now.plus({days: parsedTask.priority === 'critical' ? 1 : parsedTask.priority === 'high' ? 3 : 7}).toISO()
  }
}];

